<template>
    <div class="container">
        <div class="loading-screen"></div>

        <div class="loader">
            <div class="ringOne ring"><img src="../assets/img/ring.png" alt="Loader | thanks to Codegrid"></div>
            <div class="ringTwo ring"><img src="../assets/img/ring.png" alt="Loader | thanks to Codegrid"></div>
        </div>
    </div>
</template>

<script>
import { TweenMax, Expo, TimelineMax } from 'gsap';

export default {
  name: 'Loader',

  mounted: function() {
    this.$nextTick(function vueLoader() {
        TweenMax.to(".loading-screen", 4, {
            delay: 6.6,
            top: "-110%",
            ease: Expo.easeInOut    
        })

        let t1 = new TimelineMax()

        t1.from(".ringOne", 4, {
            delay: 0.4,
            opacity: 0,
            yPercent: 40,
            ease: Expo.easeInOut
        }).from(".ringTwo", 4, {
                delay: 0.9,
                opacity: 0,
                yPercent: 40,
                ease: Expo.easeInOut
        }, "-=5").to(".ringOne", 4, {
                delay: 0.4,
                xPercent: 14,
                ease: Expo.easeInOut
        }).to(".ringTwo", 4, {
                delay: 0.9,
                xPercent: 14,
                ease: Expo.easeInOut
        },"-=5");
    })
  }
}
</script>

<style lang="scss" scoped>
    .loading-screen {
        position: absolute;
        width: 100%;
        height: 100vh;
        background: #0a0a0a;
        z-index: 2;
    }

    .ring {
        margin: 0;
        padding: 0;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        position: absolute;
        z-index: 2;
        width: 40%;
        opacity: 0.7;
    }

    .ringOne {
        img {
            animation: rotateRing 2s linear infinite; 
        }
    }

    .ringTwo {
        img {
            animation: rotateRing 8s linear infinite; 
        }
    }

    @keyframes rotateRing { 
        from {
            transform: rotate(0deg);
        }
        to {
            transform: rotate(360deg);
        }
    }

    @media (max-width: 900px) {
        .loading-screen {
            top: 0;
            left: 0;
        }
    }
</style>
